这里的 `ReadParamToString(readParams)` 是昂贵构造，但不用提前通过 `ShouldRecord()` 控制。把 `ValidateReadParams` 改成只接收 `AccessRecorder &`：

```cpp
Status ValidateReadParams(const std::vector<ReadParam> &readParams, AccessRecorder &accessPoint)
{
    int64_t dataSize = 0;
    std::unordered_set<std::string> keys;
    for (const auto &param : readParams) {
        if (keys.find(param.key) != keys.end()) {
            auto status = Status(K_INVALID, FormatString("The input parameter contains duplicate key %s. Keys: %s",
                                                         param.key, VectorToString(keys)));
            accessPoint.Record(K_INVALID, dataSize, [&](RequestParam &req) {
                req.objectKey = ReadParamToString(readParams);
                req.timeout = "0";
            }, status.GetMsg());
            return status;
        }
        ...
    }
    return Status::OK();
}
```

